    obj=json.loads(s)
    print('json ok')
except Exception as e:
    print('json fail',e)
    # trim trailing non-json bytes if any
    idx=s.rfind('}')
    if idx!=-1:
        try:
            obj=json.loads(s[:idx+1])
            print('json trim ok')
        except Exception as e2:
            print('json trim fail',e2)

if obj is None:
    raise SystemExit

out_dir=Path('/Users/pedromousinho/Downloads/recovery-2026-02-20')
(out_dir/'chat_conversation_cache_response_full.json').write_text(json.dumps(obj,ensure_ascii=False,indent=2),encoding='utf-8')

msgs=obj.get('chat_messages',[])
print('messages',len(msgs))

# Extract tool create_file payloads with file_text
recovered=[]
for m in msgs:
    for c in m.get('content',[]):
        if c.get('type')=='tool_use' and c.get('name')=='create_file':
            inp=c.get('input',{})
            path=inp.get('path')
            text=inp.get('file_text')
            if path and isinstance(text,str):
                fname=path.split('/')[-1]
                save=out_dir/f'from-cache-{fname}'
                save.write_text(text,encoding='utf-8')
                recovered.append((fname,len(text),m.get('created_at'),save))

# Extract assistant visible texts around target times
assistant_texts=[]
for m in msgs:
    if m.get('sender')!='assistant':
        continue
    chunks=[]
    for c in m.get('content',[]):
        if c.get('type')=='text' and isinstance(c.get('text'),str):
            chunks.append(c.get('text'))
    if chunks:
        text='\n'.join(chunks)
        assistant_texts.append((m.get('created_at'),m.get('uuid'),text))

# Save all assistant texts
with (out_dir/'assistant-texts-full.txt').open('w',encoding='utf-8') as f:
    for i,(ts,uid,t) in enumerate(assistant_texts,1):
        f.write(f'=== assistant message {i} | {ts} | {uid} ===\n{t}\n\n')

# Find the specific message snippet shown in screenshot and surrounding assistant messages
needle='Vou analisar o ZIP que está a funcionar em produção e criar ambos os manuais.'
idx=-1
for i,(ts,uid,t) in enumerate(assistant_texts):
    if needle in t:
        idx=i
        break
print('assistant needle index',idx)
if idx!=-1:
    with (out_dir/'assistant-around-lost-thread.txt').open('w',encoding='utf-8') as f:
